#include <assert.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <chrono>
#include <omp.h>

#define MAX_MASK_WIDTH 10
#define MAX_BLOCK_SIZE 1024

template<typename T>
void conv1d_target(const T *in,
                   T *out,
                   const int input_width,
                   const int mask_width,
                   const T *mask)
{
  #pragma omp target
  {
    #pragma omp teams num_teams(input_width / omp_get_num_threads())
    #pragma omp distribute
    {
      int i = omp_get_thread_num() + omp_get_team_num() * omp_get_num_threads();
      T s = 0;
      int start = i - mask_width / 2;
      for (int j = 0; j < mask_width; j++) {
        if (start + j >= 0 && start + j < input_width) {
          s += in[start + j] * mask[j];
        }
      }
      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled_target(const T *in,
                         T *out,
                         const int input_width,
                         const int mask_width,
                         const T *mask,
                         int block_size)
{
  #pragma omp target
  {
    #pragma omp teams num_teams(input_width / block_size) thread_limit(block_size)
    {
      T tile[block_size + MAX_MASK_WIDTH - 1];

      int tid = omp_get_thread_num();
      int team = omp_get_team_num();
      int n = mask_width / 2;

      #pragma omp barrier

      int halo_left = (team - 1) * block_size + tid;
      if (tid >= block_size - n)
        tile[tid - (block_size - n)] = halo_left < 0 ? 0 : in[halo_left];

      tile[n + tid] = in[team * block_size + tid];

      int halo_right = (team + 1) * block_size + tid;
      if (tid < n)
        tile[tid + block_size + n] = halo_right >= input_width ? 0 : in[halo_right];

      #pragma omp barrier

      int i = tid + team * block_size;
      T s = 0;
      for (int j = 0; j < mask_width; j++)
        s += tile[tid + j] * mask[j];

      out[i] = s;
    }
  }
}

template<typename T>
void conv1d_tiled_caching_target(const T *in,
                                 T *out,
                                 const int input_width,
                                 const int mask_width,
                                 const T *mask,
                                 int block_size)
{
  #pragma omp target
  {
    #pragma omp teams num_teams(input_width / block_size) thread_limit(block_size)
    {
      T tile[block_size];

      int tid = omp_get_thread_num();
      int team = omp_get_team_num();
      int i = tid + team * block_size;

      tile[tid] = in[i];

      #pragma omp barrier

      int this_tile_start = team * block_size;
      int next_tile_start = (team + 1) * block_size;
      int start = i - (mask_width / 2);
      T s = 0;
      for (int j = 0; j < mask_width; j++) {
        int in_index = start + j;
        if (in_index >= 0 && in_index < input_width) {
          if (in_index >= this_tile_start && in_index < next_tile_start) {
            s += tile[tid + j - (mask_width / 2)] * mask[j];
          } else {
            s += in[in_index] * mask[j];
          }
        }
      }
      out[i] = s;
    }
  }
}

template <typename T>
void reference(const T *h_in,
               const T *d_out,
               const T *mask,
               const int input_width,
               const int mask_width)
{
  bool ok = true;
  for (int i = 0; i < input_width; i++) {
    T s = 0;
    int start = i - mask_width / 2;
    for (int j = 0; j < mask_width; j++) {
      if (start + j >= 0 && start + j < input_width) {
        s += h_in[start + j] * mask[j];
      }
    }
    if (fabs(s - d_out[i]) > 1e-3) {
      ok = false;
      break;
    }
  }
  printf("%s\n", ok ? "PASS" : "FAIL");
}

template <typename T>
void conv1D(const int input_width, const int mask_width, const int repeat)
{
  size_t size_bytes = input_width * sizeof(T);

  T *a, *b;
  a = (T *)malloc(size_bytes); 
  b = (T *)malloc(size_bytes); 

  T h_mask[MAX_MASK_WIDTH];

  for (int i = 0; i < MAX_MASK_WIDTH; i++) h_mask[i] = 1; 

  srand(123);
  for (int i = 0; i < input_width; i++) {
    a[i] = rand() % 256;
  }

  T *d_a, *d_b;
  d_a = (T *)malloc(size_bytes);
  d_b = (T *)malloc(size_bytes);

  #pragma omp target copyin(a[0:input_width]) copyout(d_a[0:input_width])
  {
    for (int i = 0; i < input_width; i++) {
      d_a[i] = a[i];
    }
  }

  #pragma omp target
  {
    #pragma omp teams num_teams(1)
    #pragma omp distribute
    {
      for (int i = 0; i < input_width; i++) {
        d_b[i] = 0;
      }
    }
  }

  // conv1d kernel
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_target<T>(d_a, d_b, input_width, mask_width, h_mask);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);

    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  // conv1d_tiled kernel
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_target<T>(d_a, d_b, input_width, mask_width, h_mask, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);

    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  // conv1d_tiled_caching kernel
  for (int bs = 64; bs <= MAX_BLOCK_SIZE; bs = bs * 2) {
    auto start = std::chrono::steady_clock::now();
    for (int i = 0; i < repeat; i++) {
      conv1d_tiled_caching_target<T>(d_a, d_b, input_width, mask_width, h_mask, bs);
    }
    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    printf("Average kernel execution time of conv1d-tiled-caching kernel (block size %d): %f (us)\n",
           bs, (time * 1e-3f) / repeat);

    #pragma omp target copyout(b[0:input_width])
    {
      for (int i = 0; i < input_width; i++) {
        b[i] = d_b[i];
      }
    }
    reference(a, b, h_mask, input_width, mask_width);
  }

  free(a);
  free(b);
  free(d_a);
  free(d_b);
}

int main(int argc, char* argv[]) {
  if (argc != 3) {
    printf("Usage: %s <input_width> <repeat>\n", argv[0]);
    return 1;
  }

  int input_width = atoi(argv[1]);

  input_width = (input_width + MAX_BLOCK_SIZE - 1) / MAX_BLOCK_SIZE * MAX_BLOCK_SIZE;

  const int repeat = atoi(argv[2]);

  for (int mask_width = 3; mask_width < MAX_MASK_WIDTH; mask_width += 2) {
    printf("\n---------------------\n");
    printf("Mask width: %d\n", mask_width); 

    printf("1D convolution (FP64)\n");
    conv1D<double>(input_width, mask_width, repeat);

    printf("1D convolution (FP32)\n");
    conv1D<float>(input_width, mask_width, repeat);

    printf("1D convolution (INT16)\n");
    conv1D<int16_t>(input_width, mask_width, repeat);
  }

  return 0;
}
